// ══════════════════════════════════════════════════════════════════════════════
// SPARTAN CAD INTEGRATION — new-tab + postMessage bridge
// ══════════════════════════════════════════════════════════════════════════════
var SPARTAN_CAD_B64 = '';
var _cadModal = null;
var _cadBlobUrl = null;
var _cadAckHandler = null;

// ── Multi-quote UI & helpers (spec §3.2) ────────────────────────────────────
// The deal detail page lists every entry in deal.quotes[] with Edit / Open PDF /
// Delete actions, highlights the active one, and offers "+ New Quote". All
// helpers here operate on deals only; leads/jobs come in later steps.

function getDealActiveQuote(deal) {
  if (!deal || !Array.isArray(deal.quotes) || deal.quotes.length === 0) return null;
  if (deal.activeQuoteId) {
    var found = deal.quotes.find(function(q){ return q.id === deal.activeQuoteId; });
    if (found) return found;
  }
  return deal.quotes[0];
}

// Spec §3.3: deal.val is derived from the active quote's totalPrice when quotes exist.
// Used by UI readers; aggregations (kanban totals, forecasts) continue to read d.val
// directly because the save handler writes the active quote's price back into d.val.
function getDealDisplayValue(deal) {
  var aq = getDealActiveQuote(deal);
  if (aq && typeof aq.totalPrice === 'number') return aq.totalPrice;
  return deal.val || 0;
}

function renderDealQuoteList(d) {
  var quotes = Array.isArray(d.quotes) ? d.quotes : [];
  var activeId = d.activeQuoteId || null;
  var wonId = d.wonQuoteId || null;
  // Step 4 §3: once a deal has a wonQuoteId, parts of the quote UI lock down.
  var isDealWon = !!wonId;

  var rowsHtml;
  if (quotes.length === 0) {
    rowsHtml = '<div style="font-size:12px;color:#9ca3af;padding:10px 0">No quotes yet \u2014 click "+ New Quote" to start a design.</div>';
  } else {
    rowsHtml = quotes.map(function(q) {
      var isActive = q.id === activeId;
      var isWon = wonId && q.id === wonId;
      var frameCount = (typeof q.frameCount === 'number') ? q.frameCount : (q.projectItems||[]).length;
      var savedAtStr = q.savedAt ? new Date(q.savedAt).toLocaleDateString('en-AU') : '\u2014';
      var rowBg = isActive ? '#f0fdf4' : '#ffffff';
      var rowBorder = isActive ? '#86efac' : '#e5e7eb';
      var pdfBtn = (q.pdfBase64 || q.pdf)
        ? '<button onclick="openQuotePdf(\''+d.id+'\',\''+q.id+'\')" title="Open PDF" style="padding:4px 8px;border:1px solid #e5e7eb;border-radius:5px;background:#fff;cursor:pointer;font-size:11px">\ud83d\udcc4 PDF</button>'
        : '<button disabled title="No PDF yet \u2014 CAD generates it on save (v2.0+)" style="padding:4px 8px;border:1px solid #f3f4f6;border-radius:5px;background:#f9fafb;color:#d1d5db;cursor:not-allowed;font-size:11px">\ud83d\udcc4 PDF</button>';
      var deleteBtn = isWon
        ? '<button disabled title="Cannot delete the won quote" style="padding:4px 8px;border:1px solid #f3f4f6;border-radius:5px;background:#f9fafb;color:#d1d5db;cursor:not-allowed;font-size:11px">\ud83d\uddd1 Delete</button>'
        : '<button onclick="deleteDealQuote(\''+d.id+'\',\''+q.id+'\')" title="Delete quote" style="padding:4px 8px;border:1px solid #fecaca;border-radius:5px;background:#fff;color:#b91c1c;cursor:pointer;font-size:11px">\ud83d\uddd1 Delete</button>';
      var setActiveBtn = isActive
        ? '<span style="font-size:10px;font-weight:700;color:#15803d;padding:4px 6px">\u2714 Active</span>'
        : '<button onclick="setActiveDealQuote(\''+d.id+'\',\''+q.id+'\')" title="Make this the active quote" style="padding:4px 8px;border:1px solid #e5e7eb;border-radius:5px;background:#fff;cursor:pointer;font-size:11px;color:#6b7280">Set active</button>';
      // Step 4 §3: the won quote's Edit button becomes View (read-only CAD).
      // Non-won quotes still open in design mode even on won deals — users may
      // want to iterate on rejected quotes for records.
      var editBtn = isWon
        ? '<button onclick="viewDealQuote(\''+d.id+'\',\''+q.id+'\')" title="Open in CAD (read-only)" style="padding:4px 10px;border:1px solid #86efac;border-radius:5px;background:#f0fdf4;color:#15803d;cursor:pointer;font-size:11px;font-weight:600">\ud83d\udc41 View</button>'
        : '<button onclick="editDealQuote(\''+d.id+'\',\''+q.id+'\')" title="Open in CAD" style="padding:4px 10px;border:none;border-radius:5px;background:#c41230;color:#fff;cursor:pointer;font-size:11px;font-weight:600">\u270f Edit</button>';
      return '<div style="display:grid;grid-template-columns:1fr auto;gap:8px;padding:10px;background:'+rowBg+';border:1px solid '+rowBorder+';border-radius:8px;margin-bottom:6px">'
        +  '<div style="min-width:0">'
        +    '<div style="font-size:12px;font-weight:700;color:#1a1a1a;display:flex;align-items:center;gap:6px">'
        +      (q.label||'Quote')
        +      (isWon ? '<span style="font-size:9px;font-weight:700;color:#15803d;background:#dcfce7;padding:1px 6px;border-radius:3px">WON</span>' : '')
        +    '</div>'
        +    '<div style="font-size:11px;color:#6b7280;margin-top:2px">'+frameCount+' frame'+(frameCount===1?'':'s')+' \u00b7 $'+Math.round(q.totalPrice||0).toLocaleString()+'</div>'
        +    '<div style="font-size:10px;color:#9ca3af;margin-top:2px">Saved: '+savedAtStr+'</div>'
        +  '</div>'
        +  '<div style="display:flex;flex-direction:column;gap:4px;align-items:flex-end">'
        +    setActiveBtn
        +    '<div style="display:flex;gap:4px">'
        +      editBtn
        +      pdfBtn
        +      deleteBtn
        +    '</div>'
        +  '</div>'
        +'</div>';
    }).join('');
  }

  // Step 4 §3: "+ New Quote" is locked once a won quote exists.
  var newQuoteBtn = isDealWon
    ? '<button disabled title="This deal is won \u2014 quote selection is locked." style="font-size:12px;width:100%;justify-content:center;gap:6px;margin-top:8px;padding:8px;border:1px solid #e5e7eb;border-radius:8px;background:#f9fafb;color:#9ca3af;cursor:not-allowed">+ New Quote</button>'
    : '<button onclick="newDealQuote(\''+d.id+'\')" class="btn-r" style="font-size:12px;width:100%;justify-content:center;gap:6px;margin-top:8px">+ New Quote</button>';

  return '<div style="padding:16px;border-bottom:1px solid #f0f0f0">'
    +    '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px">'
    +      '<div style="font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#6b7280">\ud83c\udfae Design \u00b7 Quotes</div>'
    +      (quotes.length > 0 ? '<span style="font-size:10px;color:#9ca3af">'+quotes.length+' quote'+(quotes.length===1?'':'s')+'</span>' : '')
    +    '</div>'
    +    rowsHtml
    +    newQuoteBtn
    +  '</div>';
}

// CRUD operations on deal.quotes[]. All of these call setState (re-renders the
// page) and dbUpdate (persists). Kept fire-and-forget for the DB; the UI is
// optimistic and matches the rest of the app's conventions.
function _dealPatch(dealId, patchFn) {
  var deals = (getState().deals || []).map(function(d) {
    if (d.id !== dealId) return d;
    var next = Object.assign({}, d);
    patchFn(next);
    return next;
  });
  setState({ deals: deals });
  var updated = deals.find(function(d){ return d.id === dealId; });
  if (updated) {
    // Persist the full multi-quote surface + the mirror so DB and memory stay in sync.
    dbUpdate('deals', dealId, {
      quotes: updated.quotes || [],
      active_quote_id: updated.activeQuoteId || null,
      won_quote_id: updated.wonQuoteId || null,
      cad_data: updated.cadData || null,
      val: updated.val || 0
    });
  }
}

function setActiveDealQuote(dealId, quoteId) {
  // Step 4 §3: if a deal is already won, switching the "active" quote must not
  // move the mirror or deal.val off the won quote — those are locked. We still
  // update activeQuoteId so the UI highlights which quote the rep is viewing.
  var deal = (getState().deals||[]).find(function(d){ return d.id === dealId; });
  var isLockedWon = !!(deal && deal.wonQuoteId);
  if (isLockedWon && quoteId !== deal.wonQuoteId) {
    _dealPatch(dealId, function(d){ d.activeQuoteId = quoteId; });
    addToast("This won't change the won quote \u2014 that's locked.", 'warning');
    return;
  }
  _dealPatch(dealId, function(d) {
    d.activeQuoteId = quoteId;
    // Spec §3.3: deal.val tracks the active quote's totalPrice while the deal is open.
    var aq = (d.quotes||[]).find(function(q){ return q.id === quoteId; });
    if (aq && typeof aq.totalPrice === 'number') d.val = aq.totalPrice;
    // Keep the cadData mirror in sync so existing readers (job creation, etc.) see the active design.
    if (aq) {
      d.cadData = {
        projectItems: aq.projectItems || [],
        totalPrice: aq.totalPrice || 0,
        savedAt: aq.savedAt || null,
        quoteNumber: aq.quoteNumber || '',
        projectName: (d.cadData && d.cadData.projectName) || d.title || ''
      };
    }
  });
  addToast('Active quote set', 'success');
}

// Step 4 §3: read-only CAD view for the won quote. Sets activeQuoteId so CAD
// opens on the right quote, then launches in 'view' mode (CAD honours this;
// older CAD builds fall back to 'design', which is still benign for read-only
// intent since no save is triggered from this path).
function viewDealQuote(dealId, quoteId) {
  _dealPatch(dealId, function(d){ d.activeQuoteId = quoteId; });
  openCadDesigner('deal', dealId, 'view');
}

function editDealQuote(dealId, quoteId) {
  _dealPatch(dealId, function(d){ d.activeQuoteId = quoteId; });
  openCadDesigner('deal', dealId, 'design');
}

function newDealQuote(dealId) {
  // Clear activeQuoteId so openCadDesigner sees null and CAD starts a blank canvas.
  // The save handler will allocate q_N+1 when CAD returns quoteId:null.
  _dealPatch(dealId, function(d){ d.activeQuoteId = null; });
  openCadDesigner('deal', dealId, 'design');
}

function deleteDealQuote(dealId, quoteId) {
  var deal = (getState().deals||[]).find(function(d){ return d.id === dealId; });
  if (!deal) return;
  if (deal.wonQuoteId && deal.wonQuoteId === quoteId) {
    addToast('Cannot delete the won quote', 'error');
    return;
  }
  var quote = (deal.quotes||[]).find(function(q){ return q.id === quoteId; });
  if (!quote) return;
  if (!confirm('Delete "' + (quote.label||'this quote') + '"? This cannot be undone.')) return;

  _dealPatch(dealId, function(d) {
    d.quotes = (d.quotes||[]).filter(function(q){ return q.id !== quoteId; });
    if (d.activeQuoteId === quoteId) {
      d.activeQuoteId = d.quotes[0] ? d.quotes[0].id : null;
      // Re-sync val + cadData to the new active quote (or clear if no quotes left).
      var newActive = d.quotes[0];
      if (newActive) {
        d.val = newActive.totalPrice || d.val || 0;
        d.cadData = {
          projectItems: newActive.projectItems || [],
          totalPrice: newActive.totalPrice || 0,
          savedAt: newActive.savedAt || null,
          quoteNumber: newActive.quoteNumber || '',
          projectName: (d.cadData && d.cadData.projectName) || d.title || ''
        };
      } else {
        d.cadData = null;
      }
    }
  });
  addToast('Quote deleted', 'success');
}

function openQuotePdf(dealId, quoteId) {
  var deal = (getState().deals||[]).find(function(d){ return d.id === dealId; });
  if (!deal) return;
  var quote = (deal.quotes||[]).find(function(q){ return q.id === quoteId; });
  if (!quote) return;
  var b64 = quote.pdfBase64 || quote.pdf;
  if (!b64) { addToast('No PDF on this quote yet', 'warning'); return; }
  try {
    var dataUrl = 'data:application/pdf;base64,' + b64;
    window.open(dataUrl, '_blank');
  } catch(e) { addToast('Could not open PDF', 'error'); }
}

// ── Lead-side multi-quote helpers (spec §3.1 final paragraph + §3.2) ────────
// Parallel to the deal-side helpers above. Leads have quotes[] + activeQuoteId,
// but NO wonQuoteId concept (leads aren't "won" — they convert). On conversion,
// lead.quotes is copied verbatim into the new deal (see _executeLead2Deal).

function getLeadActiveQuote(lead) {
  if (!lead || !Array.isArray(lead.quotes) || lead.quotes.length === 0) return null;
  if (lead.activeQuoteId) {
    var found = lead.quotes.find(function(q){ return q.id === lead.activeQuoteId; });
    if (found) return found;
  }
  return lead.quotes[0];
}

// Mirror of getDealDisplayValue for leads — used by the lead detail header so
// the displayed value tracks whatever quote is currently active.
function getLeadDisplayValue(lead) {
  var aq = getLeadActiveQuote(lead);
  if (aq && typeof aq.totalPrice === 'number') return aq.totalPrice;
  return lead.val || 0;
}

function renderLeadQuoteList(l) {
  var quotes = Array.isArray(l.quotes) ? l.quotes : [];
  var activeId = l.activeQuoteId || null;

  var rowsHtml;
  if (quotes.length === 0) {
    rowsHtml = '<div style="font-size:12px;color:#9ca3af;padding:10px 0">No quotes yet \u2014 click "+ New Quote" to start a preliminary design.</div>';
  } else {
    rowsHtml = quotes.map(function(q) {
      var isActive = q.id === activeId;
      var frameCount = (typeof q.frameCount === 'number') ? q.frameCount : (q.projectItems||[]).length;
      var savedAtStr = q.savedAt ? new Date(q.savedAt).toLocaleDateString('en-AU') : '\u2014';
      var rowBg = isActive ? '#f0fdf4' : '#ffffff';
      var rowBorder = isActive ? '#86efac' : '#e5e7eb';
      var pdfBtn = (q.pdfBase64 || q.pdf)
        ? '<button onclick="openLeadQuotePdf(\''+l.id+'\',\''+q.id+'\')" title="Open PDF" style="padding:4px 8px;border:1px solid #e5e7eb;border-radius:5px;background:#fff;cursor:pointer;font-size:11px">\ud83d\udcc4 PDF</button>'
        : '<button disabled title="No PDF yet \u2014 CAD generates it on save (v2.0+)" style="padding:4px 8px;border:1px solid #f3f4f6;border-radius:5px;background:#f9fafb;color:#d1d5db;cursor:not-allowed;font-size:11px">\ud83d\udcc4 PDF</button>';
      // Leads have no wonQuoteId — every quote is freely deletable.
      var deleteBtn = '<button onclick="deleteLeadQuote(\''+l.id+'\',\''+q.id+'\')" title="Delete quote" style="padding:4px 8px;border:1px solid #fecaca;border-radius:5px;background:#fff;color:#b91c1c;cursor:pointer;font-size:11px">\ud83d\uddd1 Delete</button>';
      var setActiveBtn = isActive
        ? '<span style="font-size:10px;font-weight:700;color:#15803d;padding:4px 6px">\u2714 Active</span>'
        : '<button onclick="setActiveLeadQuote(\''+l.id+'\',\''+q.id+'\')" title="Make this the active quote" style="padding:4px 8px;border:1px solid #e5e7eb;border-radius:5px;background:#fff;cursor:pointer;font-size:11px;color:#6b7280">Set active</button>';
      return '<div style="display:grid;grid-template-columns:1fr auto;gap:8px;padding:10px;background:'+rowBg+';border:1px solid '+rowBorder+';border-radius:8px;margin-bottom:6px">'
        +  '<div style="min-width:0">'
        +    '<div style="font-size:12px;font-weight:700;color:#1a1a1a">'+(q.label||'Quote')+'</div>'
        +    '<div style="font-size:11px;color:#6b7280;margin-top:2px">'+frameCount+' frame'+(frameCount===1?'':'s')+' \u00b7 $'+Math.round(q.totalPrice||0).toLocaleString()+'</div>'
        +    '<div style="font-size:10px;color:#9ca3af;margin-top:2px">Saved: '+savedAtStr+'</div>'
        +  '</div>'
        +  '<div style="display:flex;flex-direction:column;gap:4px;align-items:flex-end">'
        +    setActiveBtn
        +    '<div style="display:flex;gap:4px">'
        +      '<button onclick="editLeadQuote(\''+l.id+'\',\''+q.id+'\')" title="Open in CAD" style="padding:4px 10px;border:none;border-radius:5px;background:#c41230;color:#fff;cursor:pointer;font-size:11px;font-weight:600">\u270f Edit</button>'
        +      pdfBtn
        +      deleteBtn
        +    '</div>'
        +  '</div>'
        +'</div>';
    }).join('');
  }

  return '<div style="padding:16px;border-bottom:1px solid #f0f0f0">'
    +    '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px">'
    +      '<div style="font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#6b7280">\ud83c\udfae Design \u00b7 Quotes</div>'
    +      (quotes.length > 0 ? '<span style="font-size:10px;color:#9ca3af">'+quotes.length+' quote'+(quotes.length===1?'':'s')+'</span>' : '')
    +    '</div>'
    +    rowsHtml
    +    '<button onclick="newLeadQuote(\''+l.id+'\')" class="btn-r" style="font-size:12px;width:100%;justify-content:center;gap:6px;margin-top:8px">+ New Quote</button>'
    +  '</div>';
}

// Lead-side patch helper. Writes through to dbUpdate('leads', ...) with the
// same snake_case keys as the leadToDb mapping — but NOT won_quote_id, because
// leads never have a won quote (it stays null in the DB).
function _leadPatch(leadId, patchFn) {
  var leads = (getState().leads || []).map(function(l) {
    if (l.id !== leadId) return l;
    var next = Object.assign({}, l);
    patchFn(next);
    return next;
  });
  setState({ leads: leads });
  var updated = leads.find(function(l){ return l.id === leadId; });
  if (updated) {
    dbUpdate('leads', leadId, {
      quotes: updated.quotes || [],
      active_quote_id: updated.activeQuoteId || null,
      cad_data: updated.cadData || null,
      val: updated.val || 0
    });
  }
}

function setActiveLeadQuote(leadId, quoteId) {
  _leadPatch(leadId, function(l) {
    l.activeQuoteId = quoteId;
    var aq = (l.quotes||[]).find(function(q){ return q.id === quoteId; });
    if (aq && typeof aq.totalPrice === 'number') l.val = aq.totalPrice;
    if (aq) {
      l.cadData = {
        projectItems: aq.projectItems || [],
        totalPrice: aq.totalPrice || 0,
        savedAt: aq.savedAt || null,
        quoteNumber: aq.quoteNumber || '',
        projectName: (l.cadData && l.cadData.projectName) || ((l.fn||'')+' '+(l.ln||'')) || ''
      };
    }
  });
  addToast('Active quote set', 'success');
}

function editLeadQuote(leadId, quoteId) {
  _leadPatch(leadId, function(l){ l.activeQuoteId = quoteId; });
  openCadDesigner('lead', leadId, 'design');
}

function newLeadQuote(leadId) {
  // Clear activeQuoteId so openCadDesigner sees null → CAD starts a blank canvas.
  // The save handler will allocate q_N+1 when CAD returns quoteId:null.
  _leadPatch(leadId, function(l){ l.activeQuoteId = null; });
  openCadDesigner('lead', leadId, 'design');
}

function deleteLeadQuote(leadId, quoteId) {
  var lead = (getState().leads||[]).find(function(l){ return l.id === leadId; });
  if (!lead) return;
  var quote = (lead.quotes||[]).find(function(q){ return q.id === quoteId; });
  if (!quote) return;
  if (!confirm('Delete "' + (quote.label||'this quote') + '"? This cannot be undone.')) return;

  _leadPatch(leadId, function(l) {
    l.quotes = (l.quotes||[]).filter(function(q){ return q.id !== quoteId; });
    if (l.activeQuoteId === quoteId) {
      l.activeQuoteId = l.quotes[0] ? l.quotes[0].id : null;
      var newActive = l.quotes[0];
      if (newActive) {
        l.val = newActive.totalPrice || l.val || 0;
        l.cadData = {
          projectItems: newActive.projectItems || [],
          totalPrice: newActive.totalPrice || 0,
          savedAt: newActive.savedAt || null,
          quoteNumber: newActive.quoteNumber || '',
          projectName: (l.cadData && l.cadData.projectName) || ((l.fn||'')+' '+(l.ln||'')) || ''
        };
      } else {
        l.cadData = null;
      }
    }
  });
  addToast('Quote deleted', 'success');
}

function openLeadQuotePdf(leadId, quoteId) {
  var lead = (getState().leads||[]).find(function(l){ return l.id === leadId; });
  if (!lead) return;
  var quote = (lead.quotes||[]).find(function(q){ return q.id === quoteId; });
  if (!quote) return;
  var b64 = quote.pdfBase64 || quote.pdf;
  if (!b64) { addToast('No PDF on this quote yet', 'warning'); return; }
  try {
    var dataUrl = 'data:application/pdf;base64,' + b64;
    window.open(dataUrl, '_blank');
  } catch(e) { addToast('Could not open PDF', 'error'); }
}

function openCadDesigner(entityType, entityId, mode) {
  var contacts = getState().contacts || [];
  var entity = null;
  if (entityType === 'deal') entity = (getState().deals||[]).find(function(d){return d.id===entityId;});
  else if (entityType === 'job') entity = (getState().jobs||[]).find(function(j){return j.id===entityId;});
  else if (entityType === 'lead') entity = (getState().leads||[]).find(function(l){return l.id===entityId;});
  if (!entity) { addToast('Record not found','error'); return; }

  // Step 5 §5.3: final-mode guards (spec §4.4). Check Measure must be completed
  // before Final Design can start. A signed Final Design is view-only (we warn
  // but still open the overlay — the user can open CAD in read-only for audit).
  if (mode === 'final' && entityType === 'job') {
    if (!entity.cmCompletedAt) {
      addToast('Check Measure must be completed before Final Design', 'error');
      return;
    }
    if (entity.finalSignedAt) {
      addToast('Final Design is signed — opened in view-only', 'warning');
      // fall through: viewing is allowed
    }
  }

  var contact = contacts.find(function(c){return c.id===(entity.cid||entity.contactId);});
  if (entityType === 'lead' && !contact) contact = {fn:entity.fn||'',ln:entity.ln||'',phone:entity.phone||'',email:entity.email||''};
  _cadModal = {entityType:entityType, entityId:entityId, mode:mode||'design'};
  var entityLabel = entityType === 'deal' ? 'Deal' : entityType === 'job' ? 'Job' : 'Lead';
  // Step 5 §3.3: for the two new job-side modes, the Save button label should
  // reflect the mode, not the entity type. 'Save to Job' is ambiguous when
  // there are three job-side modes; 'Save Survey' / 'Save Final Design' is clearer.
  var saveButtonLabel = 'Save to ' + entityLabel;
  if (entityType === 'job' && mode === 'survey') saveButtonLabel = 'Save Survey';
  else if (entityType === 'job' && mode === 'final') saveButtonLabel = 'Save Final Design';

  var initPayload = {
    type: 'spartan-cad-init', mode: mode || 'design',
    entityType: entityType, entityId: entityId,
    customer: contact ? {name:(contact.fn||'')+' '+(contact.ln||''), phone:contact.phone||'', email:contact.email||'', address:[entity.street,entity.suburb,entity.state,entity.postcode].filter(Boolean).join(', ')} : {},
    projectName: entity.title || entity.jobNumber || ((entity.fn||'')+' '+(entity.ln||'')) || '',
    branch: entity.branch || '',
    // Multi-quote context (spec §2.1). Deals + leads both carry quotes; jobs
    // fall back to [] / null (survey/final modes are later steps).
    quotes: ((entityType === 'deal' || entityType === 'lead') && Array.isArray(entity.quotes)) ? entity.quotes : [],
    activeQuoteId: (entityType === 'deal' || entityType === 'lead') ? (entity.activeQuoteId || null) : null,
    designData: entity.cadData || null, surveyData: entity.cadSurveyData || null,
  };

  // Step 5 §3.1: job-side mode-specific init payload shaping (spec §4.2, §4.3).
  if (entityType === 'job' && mode === 'final') {
    // Spec §4.3: final mode locks dimensions + survey measurements. CAD honours
    // lockedFields[] to grey-out those inputs. widthMm/heightMm come from the
    // survey measurements; everything else (colour, glass, opening style,
    // transom/mullion positions) remains editable.
    initPayload.lockedFields = ['widthMm', 'heightMm', 'surveyMeasurements'];
    // Seed final mode from survey data if present (surveyor's measured W×H is
    // the source of truth for frame dimensions). If a partial final is already
    // in progress, resume from that; otherwise fall back to cadData.
    initPayload.designData = entity.cadFinalData || entity.cadSurveyData || entity.cadData || null;
    initPayload.surveyData = entity.cadSurveyData || null;
  } else if (entityType === 'job' && mode === 'survey') {
    var surveySource = entity.cadSurveyData || entity.cadData || null;
    initPayload.designData = surveySource;
    // projectInfo populates the survey form letterhead in the CAD.
    initPayload.projectInfo = {
      jobNumber: entity.jobNumber || '',
      customerName: contact ? ((contact.fn||'')+' '+(contact.ln||'')).trim() : '',
      siteAddress: [entity.street, entity.suburb, entity.state, entity.postcode].filter(Boolean).join(', '),
      surveyorName: '',
    };
    // Pass projectItems directly so the CAD renders per-frame survey cards.
    var surveyItems = surveySource && Array.isArray(surveySource.projectItems) ? surveySource.projectItems : [];
    if (surveyItems.length > 0) initPayload.projectItems = surveyItems;
    // Re-hydrate from a previous partial save.
    if (entity.cadSurveyData && Array.isArray(entity.cadSurveyData.surveyMeasurements)) {
      initPayload.surveyData = entity.cadSurveyData.surveyMeasurements;
    }
    if (entity.cadSurveyData && entity.cadSurveyData.siteChecklist) {
      initPayload.siteChecklist = entity.cadSurveyData.siteChecklist;
    }
  }
  // mode='design' keeps the existing behaviour.

  // Build fullscreen overlay
  var overlay = document.createElement('div');
  overlay.id = 'cadOverlay';
  overlay.style.cssText = 'position:fixed;inset:0;z-index:9999;background:#000;display:flex;flex-direction:column';

  var toolbar = document.createElement('div');
  toolbar.style.cssText = 'height:48px;background:#0e0e0e;border-bottom:3px solid #c41230;display:flex;align-items:center;padding:0 16px;gap:12px;flex-shrink:0';
  // Step 5 §3.2: toolbar mode indicator — 'CHECK MEASURE' / 'FINAL DESIGN' / 'DESIGN'.
  var modeLabel = mode === 'survey' ? 'CHECK MEASURE' : mode === 'final' ? 'FINAL DESIGN' : 'DESIGN';
  toolbar.innerHTML = '<div onclick="closeCadDesigner()" style="cursor:pointer;display:flex;align-items:center;gap:4px;color:rgba(255,255,255,.7);font-size:11px;padding:5px 10px;border-radius:4px;background:rgba(255,255,255,.08)"><span style="font-size:16px">\u2190</span> Back to CRM</div>'
    +'<div style="width:1px;height:24px;background:rgba(255,255,255,.1)"></div>'
    +'<span style="color:#fff;font-size:12px;font-weight:700;font-family:Syne,sans-serif;letter-spacing:1px">SPARTAN <span style="font-weight:400;opacity:.4">CAD</span></span>'
    +'<span style="color:rgba(255,255,255,.5);font-size:10px">\u2014 '+modeLabel+'</span>'
    +'<span style="color:#fff;font-size:12px;font-weight:600;margin-left:8px">'+(entity.title||entity.jobNumber||(entity.fn?entity.fn+' '+entity.ln:'')||'')+'</span>'
    +(contact?'<span style="color:rgba(255,255,255,.4);font-size:11px">\u00b7 '+(contact.fn||'')+' '+(contact.ln||'')+'</span>':'')
    +'<div style="margin-left:auto;display:flex;gap:8px">'
    +'<button onclick="requestCadSave()" style="padding:6px 18px;border:none;border-radius:6px;background:#c41230;color:#fff;font-size:12px;font-weight:700;cursor:pointer;font-family:Syne,sans-serif">\u2713 '+saveButtonLabel+'</button>'
    +'<button onclick="closeCadDesigner()" style="padding:6px 14px;border:1px solid rgba(255,255,255,.2);border-radius:6px;background:transparent;color:rgba(255,255,255,.6);font-size:12px;cursor:pointer">Cancel</button></div>';
  overlay.appendChild(toolbar);

  // Decode embedded CAD and create same-origin blob iframe.
  // Decode base64 → raw bytes (Uint8Array). Do NOT pass the binary string
  // from atob() directly to Blob — Blob would re-encode it as UTF-8 and
  // double-encode every multi-byte character in the CAD HTML, producing
  // mojibake throughout the embedded CAD UI and any PDFs it generates
  // (Â· instead of ·, â€" instead of —, etc.).
  var _cadBin = atob(SPARTAN_CAD_B64);
  var _cadBytes = new Uint8Array(_cadBin.length);
  for (var i = 0; i < _cadBin.length; i++) _cadBytes[i] = _cadBin.charCodeAt(i);
  var blob = new Blob([_cadBytes], {type:'text/html;charset=utf-8'});
  _cadBlobUrl = URL.createObjectURL(blob);

  var iframe = document.createElement('iframe');
  iframe.id = 'cadIframe';
  iframe.style.cssText = 'flex:1;border:none;width:100%;background:#1a1a1a';
  iframe.src = _cadBlobUrl;
  // Retry init until CAD posts spartan-cad-ready. The CAD's message listener
  // attaches at top-level (early), but React mounts later — only after mount
  // is __cadBridge.onInit set, which is what calls setProjectItems. The CAD's
  // pre-mount buffer (lastInit) restores crmInit but skips setProjectItems,
  // so a single fire-and-forget can leave the canvas empty. Resending until
  // ack guarantees at least one init arrives after React mount.
  var _cadAcked = false;
  if (_cadAckHandler) window.removeEventListener('message', _cadAckHandler);
  _cadAckHandler = function(e) {
    if (e && e.data && e.data.type === 'spartan-cad-ready') {
      _cadAcked = true;
      window.removeEventListener('message', _cadAckHandler);
      _cadAckHandler = null;
    }
  };
  window.addEventListener('message', _cadAckHandler);
  iframe.onload = function() {
    var attempts = 0;
    var trySend = function() {
      attempts++;
      if (_cadAcked || attempts > 30 || !iframe.contentWindow) return;
      try { iframe.contentWindow.postMessage(initPayload, '*'); } catch(e) {}
      setTimeout(trySend, 300);
    };
    setTimeout(trySend, 400);
  };
  overlay.appendChild(iframe);
  document.body.appendChild(overlay);
}

function requestCadSave() {
  var iframe = document.getElementById('cadIframe');
  if (iframe && iframe.contentWindow) {
    try { iframe.contentWindow.postMessage({type:'spartan-cad-request-save'}, '*'); } catch(e){}
  }
}

function closeCadDesigner() {
  var overlay = document.getElementById('cadOverlay');
  if (overlay) overlay.remove();
  if (_cadBlobUrl) { URL.revokeObjectURL(_cadBlobUrl); _cadBlobUrl = null; }
  if (_cadAckHandler) { window.removeEventListener('message', _cadAckHandler); _cadAckHandler = null; }
  _cadModal = null;
}

// Listen for save data from CAD iframe
window.addEventListener('message', function(event) {
  var msg = event.data;
  if (!msg || msg.type !== 'spartan-cad-save' || !_cadModal) return;
  var cadPayload = {
    projectItems: msg.projectItems || [], projectName: msg.projectName || '',
    totalPrice: msg.totalPrice || 0, quoteNumber: msg.quoteNumber || '', savedAt: new Date().toISOString(),
  };
  if (_cadModal.entityType === 'deal') {
    // Spec §3.2 save routing: msg.quoteId === null means "create a new quote";
    // a matching id means "update that quote in place"; an unknown id falls
    // through to create-new so we never silently lose a save.
    var incomingQuoteId = (typeof msg.quoteId !== 'undefined') ? msg.quoteId : null;
    var deal = (getState().deals||[]).find(function(d){ return d.id === _cadModal.entityId; });
    if (!deal) { addToast('Deal not found on save', 'error'); closeCadDesigner(); return; }

    var quotes = Array.isArray(deal.quotes) ? deal.quotes.slice() : [];
    var savedQuoteId = null;
    var isNew = false;
    var frameCount = cadPayload.projectItems.length;

    if (incomingQuoteId && quotes.some(function(q){ return q.id === incomingQuoteId; })) {
      // Update in place — preserve the original label and any fields CAD didn't touch.
      quotes = quotes.map(function(q) {
        if (q.id !== incomingQuoteId) return q;
        return Object.assign({}, q, {
          projectItems: cadPayload.projectItems,
          totalPrice: cadPayload.totalPrice,
          frameCount: frameCount,
          savedAt: cadPayload.savedAt,
          quoteNumber: cadPayload.quoteNumber || q.quoteNumber || ''
          // q.label, q.notes, q.pdfBase64 preserved via Object.assign spread
        });
      });
      savedQuoteId = incomingQuoteId;
    } else {
      // Allocate the next id. Scan existing q_N ids so we don't collide even if
      // earlier quotes were deleted (e.g. existing q_1, q_3 → next is q_4, not q_3).
      var maxN = 0;
      quotes.forEach(function(q) {
        var m = (q.id || '').match(/^q_(\d+)$/);
        if (m) { var n = parseInt(m[1], 10); if (n > maxN) maxN = n; }
      });
      var nextN = maxN + 1;
      savedQuoteId = 'q_' + nextN;
      var label = msg.quoteLabel || ('Quote ' + nextN);
      quotes.push({
        id: savedQuoteId, label: label,
        projectItems: cadPayload.projectItems,
        totalPrice: cadPayload.totalPrice,
        frameCount: frameCount,
        savedAt: cadPayload.savedAt,
        quoteNumber: cadPayload.quoteNumber || '',
        notes: ''
      });
      isNew = true;
    }

    // Mirror the last-saved quote into deal.cadData for backward compat (spec §3.1).
    // Every save updates the mirror so existing cadData readers always see the latest design.
    var updates = {
      quotes: quotes,
      activeQuoteId: savedQuoteId,
      cadData: cadPayload
    };
    if (cadPayload.totalPrice > 0) updates.val = cadPayload.totalPrice;

    setState({deals: (getState().deals||[]).map(function(d){ return d.id === _cadModal.entityId ? Object.assign({}, d, updates) : d; })});
    dbUpdate('deals', _cadModal.entityId, {
      quotes: quotes,
      active_quote_id: savedQuoteId,
      cad_data: cadPayload,
      val: updates.val != null ? updates.val : deal.val
    });
    addToast('\u2705 ' + (isNew ? 'New quote saved' : 'Quote updated') + ' (' + frameCount + ' frames)', 'success');
  } else if (_cadModal.entityType === 'job') {
    // Step 5 §4: three-mode save routing (spec §4.2). Each branch writes its
    // mode-specific field plus mirrors to cadData (legacy readers at lines
    // ~11008, 11098, 11209, 11371, 14727, 14762 all key off cadData — if we
    // ever stop updating it, those displays silently fall stale).
    var job = (getState().jobs||[]).find(function(j){ return j.id === _cadModal.entityId; });
    if (!job) { addToast('Job not found on save', 'error'); closeCadDesigner(); return; }

    // Extract totals if CAD supplied them (CAD v2.0+). Legacy CAD v1.x omits
    // totals/pdfs/surveyMeasurements; fall back to null so downstream code can
    // still lean on the heuristic estimator (spec §11, plan §7).
    var totals = msg.totals || null;
    var jobUpdates = {};

    if (_cadModal.mode === 'survey') {
      var surveyExtras = {};
      if (Array.isArray(msg.surveyMeasurements)) surveyExtras.surveyMeasurements = msg.surveyMeasurements;
      if (msg.siteChecklist && typeof msg.siteChecklist === 'object') surveyExtras.siteChecklist = msg.siteChecklist;
      if (msg.trimCutList && typeof msg.trimCutList === 'object') surveyExtras.trimCutList = msg.trimCutList;
      jobUpdates.cadSurveyData = Object.assign({}, cadPayload, surveyExtras);
      // Do NOT mirror to cadData — cadData is the immutable original design
      // inherited from the won deal. Overwriting it with survey measurements
      // breaks the Original-vs-Measured variance check (both columns end up
      // identical and "0 delta — no variation needed" fires falsely).
      // Factory pipeline already prefers cadFinalData → cadSurveyData → cadData,
      // so it sees the latest signed design without us mirroring.
      logJobAudit(_cadModal.entityId, 'Survey Data Saved', cadPayload.projectItems.length + ' frames');
    } else if (_cadModal.mode === 'final') {
      // Spec §4.2: final-mode saves land on cadFinalData. Signing is a separate
      // action (Step 6 / DocuSign) — we don't stamp finalSignedAt here.
      // Same rule as survey: do NOT mirror to cadData. The original design
      // must stay frozen so Original-vs-Measured / Original-vs-Final
      // comparisons still mean something.
      jobUpdates.cadFinalData = cadPayload;
      logJobAudit(_cadModal.entityId, 'Final Design Saved', cadPayload.projectItems.length + ' frames');
    } else {
      // mode='design' — the manager-override edit path (line ~14637) or a
      // legacy / unrecognised mode. Writes cadData only.
      jobUpdates.cadData = cadPayload;
      logJobAudit(_cadModal.entityId, 'CAD Design Updated', cadPayload.projectItems.length + ' frames');
    }

    // Totals land on the job regardless of mode — they're metadata about the
    // current frames, not mode-specific. Smart Planner (spec §7.2) + Capacity
    // Planner (spec §8.2) both read these.
    if (totals) {
      if (typeof totals.installMinutes === 'number') jobUpdates.estimatedInstallMinutes = totals.installMinutes;
      if (typeof totals.productionMinutes === 'number') jobUpdates.estimatedProductionMinutes = totals.productionMinutes;
      if (totals.stationTimes && typeof totals.stationTimes === 'object') jobUpdates.stationTimes = totals.stationTimes;
    }

    // Attach PDFs if present. survey → cmDocUrl, final → finalRenderedPdfUrl.
    var hasCmPdf = _cadModal.mode === 'survey' && msg.pdfs && msg.pdfs.checkMeasure && msg.pdfs.checkMeasure.base64;
    if (hasCmPdf) {
      jobUpdates.cmDocUrl = 'data:application/pdf;base64,' + msg.pdfs.checkMeasure.base64;
    } else if (_cadModal.mode === 'final' && msg.pdfs && msg.pdfs.finalDesign && msg.pdfs.finalDesign.base64) {
      jobUpdates.finalRenderedPdfUrl = 'data:application/pdf;base64,' + msg.pdfs.finalDesign.base64;
    }

    setState({jobs: (getState().jobs||[]).map(function(j){
      return j.id === _cadModal.entityId ? Object.assign({}, j, jobUpdates) : j;
    })});

    // Persist to Supabase — only the fields we touched.
    var dbPatch = {};
    if ('cadSurveyData' in jobUpdates) dbPatch.cad_survey_data = jobUpdates.cadSurveyData;
    if ('cadFinalData' in jobUpdates) dbPatch.cad_final_data = jobUpdates.cadFinalData;
    if ('cadData' in jobUpdates) dbPatch.cad_data = jobUpdates.cadData;
    if ('estimatedInstallMinutes' in jobUpdates) dbPatch.estimated_install_minutes = jobUpdates.estimatedInstallMinutes;
    if ('estimatedProductionMinutes' in jobUpdates) dbPatch.estimated_production_minutes = jobUpdates.estimatedProductionMinutes;
    if ('stationTimes' in jobUpdates) dbPatch.station_times = jobUpdates.stationTimes;
    if ('cmDocUrl' in jobUpdates) dbPatch.cm_doc_url = jobUpdates.cmDocUrl;
    if ('finalRenderedPdfUrl' in jobUpdates) dbPatch.final_rendered_pdf_url = jobUpdates.finalRenderedPdfUrl;
    dbUpdate('jobs', _cadModal.entityId, dbPatch);

    // Auto-complete CM: add the CAD-generated PDF as the CM file, close the
    // designer, then trigger completion + 45% invoice. No manual steps needed.
    if (hasCmPdf) {
      var completingJobId = _cadModal.entityId;
      var cmFilename = msg.pdfs.checkMeasure.filename || ('CM_' + (job.jobNumber || completingJobId) + '.pdf');
      addJobFile(completingJobId, cmFilename, 'check_measure', jobUpdates.cmDocUrl);
      closeCadDesigner();
      completeCmAndInvoice(completingJobId);
      return;
    }

    // \u2500\u2500 Dev-mode auto-advance \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
    // In production each status transition is driven by an external event
    // (Accounts CRM detects the 45% paid, Mobile App fires "Tap Complete",
    // etc.). Until those integrations ship, dev mode advances the status
    // here so the visible workflow keeps up with what the user just did in
    // CAD. No-op when dev mode is off.
    //
    // We bypass transitionJobStatus / canTransition entirely. The standard
    // a\u2192c gate requires cmCompletedAt + cmDocUrl, which aren't set when
    // CAD doesn't return a PDF (e.g. dev test path). Direct setState +
    // dbUpdate keeps it simple \u2014 audit log still fires via logJobAudit.
    if (typeof isDevMode === 'function' && isDevMode()) {
      var jobAfter = (getState().jobs || []).find(function(j) { return j.id === _cadModal.entityId; });
      var curStatus = jobAfter ? jobAfter.status : null;
      var devTarget = null, devNote = '';
      if (_cadModal.mode === 'survey') {
        if (['a_check_measure', 'c4_date_change_hold'].indexOf(curStatus) >= 0) {
          devTarget = 'c_awaiting_2nd_payment';
          devNote   = 'CM saved (Dev auto-advance)';
        }
      } else if (_cadModal.mode === 'final') {
        if (['a_check_measure', 'c_awaiting_2nd_payment', 'c4_date_change_hold'].indexOf(curStatus) >= 0) {
          devTarget = 'c1_final_sign_off';
          devNote   = 'Final Design saved (Dev auto-advance)';
        }
      }
      if (devTarget && jobAfter) {
        var devNow = new Date().toISOString();
        var devCu  = (typeof getCurrentUser === 'function' && getCurrentUser()) || {id:'dev', name:'Dev'};
        var devHist = (jobAfter.statusHistory || []).concat([{
          status: devTarget, at: devNow, by: devCu.id, note: devNote,
        }]);
        var devChanges = { status: devTarget, statusHistory: devHist };
        // Stamp cmCompletedAt for survey advance so the rest of the UI (Final
        // Design tab pipeline, "CM Complete" indicator) lines up with the
        // auto-advanced status.
        if (_cadModal.mode === 'survey' && !jobAfter.cmCompletedAt) {
          devChanges.cmCompletedAt = devNow;
        }
        setState({ jobs: (getState().jobs || []).map(function(j) {
          return j.id === _cadModal.entityId ? Object.assign({}, j, devChanges) : j;
        })});
        try {
          var devDb = { status: devTarget };
          if (devChanges.cmCompletedAt) devDb.cm_completed_at = devChanges.cmCompletedAt;
          dbUpdate('jobs', _cadModal.entityId, devDb);
        } catch (e) { console.warn('[Dev advance] dbUpdate failed:', e); }
        if (typeof logJobAudit === 'function') {
          logJobAudit(_cadModal.entityId, 'Status Advanced (Dev)',
            'CAD ' + _cadModal.mode + ' save \u2192 ' + devTarget);
        }
      }
    }

    var modeCopy = _cadModal.mode === 'survey' ? 'Survey' :
                   _cadModal.mode === 'final'  ? 'Final design' : 'Design';
    addToast('\u2705 ' + modeCopy + ' saved', 'success');
  } else if (_cadModal.entityType === 'lead') {
    // Spec §3.2 save routing (leads) — same shape as the deal branch, minus
    // the wonQuoteId concept. null/unknown quoteId → allocate next q_N, matching
    // id → update in place. Last save is also mirrored into lead.cadData for
    // backward compat with code that still reads it (e.g. lead→deal conversion).
    var incomingQuoteIdL = (typeof msg.quoteId !== 'undefined') ? msg.quoteId : null;
    var lead = (getState().leads||[]).find(function(l){ return l.id === _cadModal.entityId; });
    if (!lead) { addToast('Lead not found on save', 'error'); closeCadDesigner(); return; }

    var lQuotes = Array.isArray(lead.quotes) ? lead.quotes.slice() : [];
    var savedQuoteIdL = null;
    var isNewL = false;
    var frameCountL = cadPayload.projectItems.length;

    if (incomingQuoteIdL && lQuotes.some(function(q){ return q.id === incomingQuoteIdL; })) {
      lQuotes = lQuotes.map(function(q) {
        if (q.id !== incomingQuoteIdL) return q;
        return Object.assign({}, q, {
          projectItems: cadPayload.projectItems,
          totalPrice: cadPayload.totalPrice,
          frameCount: frameCountL,
          savedAt: cadPayload.savedAt,
          quoteNumber: cadPayload.quoteNumber || q.quoteNumber || ''
        });
      });
      savedQuoteIdL = incomingQuoteIdL;
    } else {
      // Allocate next q_N — scan existing ids so we don't collide (q_1, q_3 → q_4).
      var maxNL = 0;
      lQuotes.forEach(function(q) {
        var m = (q.id || '').match(/^q_(\d+)$/);
        if (m) { var n = parseInt(m[1], 10); if (n > maxNL) maxNL = n; }
      });
      var nextNL = maxNL + 1;
      savedQuoteIdL = 'q_' + nextNL;
      var labelL = msg.quoteLabel || ('Quote ' + nextNL);
      lQuotes.push({
        id: savedQuoteIdL, label: labelL,
        projectItems: cadPayload.projectItems,
        totalPrice: cadPayload.totalPrice,
        frameCount: frameCountL,
        savedAt: cadPayload.savedAt,
        quoteNumber: cadPayload.quoteNumber || '',
        notes: ''
      });
      isNewL = true;
    }

    var leadUpdates = {
      quotes: lQuotes,
      activeQuoteId: savedQuoteIdL,
      cadData: cadPayload
    };
    if (cadPayload.totalPrice > 0) leadUpdates.val = cadPayload.totalPrice;

    setState({leads: (getState().leads||[]).map(function(l){ return l.id === _cadModal.entityId ? Object.assign({}, l, leadUpdates) : l; })});
    dbUpdate('leads', _cadModal.entityId, {
      quotes: lQuotes,
      active_quote_id: savedQuoteIdL,
      cad_data: cadPayload,
      val: leadUpdates.val != null ? leadUpdates.val : lead.val
    });
    addToast('\u2705 ' + (isNewL ? 'New quote saved' : 'Quote updated') + ' (' + frameCountL + ' frames)', 'success');
  }
  closeCadDesigner();
  renderPage();
});

function updateJobField(jobId, field, value) {
  var jobs = getState().jobs || [];
  var upd = {};
  upd[field] = value;
  setState({ jobs: jobs.map(function(j){ return j.id === jobId ? Object.assign({}, j, upd) : j; }) });
  var dbField = field.replace(/([A-Z])/g, function(m){ return '_' + m.toLowerCase(); });
  var dbChanges = {}; dbChanges[dbField] = value;
  dbUpdate('jobs', jobId, dbChanges);
}

// ── Job status transition — with gate logic, history, and persistence ───────
async function transitionJobStatus(jobId, toStatus, note) {
  var jobs = getState().jobs || [];
  var job = jobs.find(function(j){ return j.id === jobId; });
  if (!job) { addToast('Job not found', 'error'); return false; }

  var check = canTransition(job, toStatus);
  if (!check.ok) {
    addToast(check.reason, 'error');
    return false;
  }

  var cu = getCurrentUser() || {id:'system', name:'System'};
  var prevStatus = job.status;
  var historyEntry = {status: toStatus, at: new Date().toISOString(), by: cu.id, note: note || ''};
  var newHistory = (job.statusHistory || []).concat([historyEntry]);
  var isHold = toStatus === 'c4_date_change_hold';

  var updates = {
    status: toStatus,
    statusHistory: newHistory,
    hold: isHold,
  };

  // If moving to hold, store the reason
  if (isHold && note) updates.holdReason = note;

  // If returning from hold, clear hold fields
  if (prevStatus === 'c4_date_change_hold' && !isHold) {
    updates.hold = false;
    updates.holdReason = '';
  }

  // If signing off (c1 → c2/c3), stamp finalSignedAt
  if (prevStatus === 'c1_final_sign_off' && (toStatus === 'c2_order_schedule_standard' || toStatus === 'c3_order_schedule_service')) {
    if (!job.finalSignedAt) updates.finalSignedAt = new Date().toISOString();
  }

  // Optimistic update
  var updatedJob = Object.assign({}, job, updates);
  setState({jobs: jobs.map(function(j){ return j.id === jobId ? updatedJob : j; })});

  // Persist
  var dbChanges = {
    status: toStatus,
    status_history: JSON.stringify(newHistory),
    hold: updates.hold,
    hold_reason: updates.holdReason || null,
  };
  if (updates.finalSignedAt) dbChanges.final_signed_at = updates.finalSignedAt;
  dbUpdate('jobs', jobId, dbChanges);

  // Log activity
  var act = {
    id: 'a' + Date.now() + Math.random().toString(36).slice(2,6),
    type: 'note',
    text: 'Status changed: ' + getJobStatusLabel(prevStatus) + ' → ' + getJobStatusLabel(toStatus) + (note ? ' — ' + note : ''),
    date: new Date().toISOString().slice(0,10),
    by: cu.name, done: false, dueDate: '',
  };
  dbInsert('activities', actToDb(act, 'job', jobId));

  addToast('Job moved to ' + getJobStatusLabel(toStatus), 'success');
  return true;
}

